import { createParamDecorator, ExecutionContext } from '@nestjs/common';
import type { Role } from '@smartcart/shared-types';

/** Shape attached to `request.user` by `JwtAuthGuard` (the JWT access claims). */
export interface AuthenticatedUser {
  sub: string;
  role: Role;
  email?: string;
}

/**
 * `@CurrentUser()` — extracts the authenticated user from the request
 * (README §2.2 Rule 4). Use only on JWT-guarded routes.
 */
export const CurrentUser = createParamDecorator(
  (_data: unknown, ctx: ExecutionContext): AuthenticatedUser => {
    const request = ctx
      .switchToHttp()
      .getRequest<{ user: AuthenticatedUser }>();
    return request.user;
  },
);
